// ========================================
// Node: Parse & Enrich Error Log
// ========================================
const body = $input.first().json.body || $input.first().json;

// Validate required fields
const required = ['service', 'level', 'message'];
for (const field of required) {
  if (!body[field]) {
    throw new Error(`Missing required field: ${field}`);
  }
}

// Normalize log level
const level = (body.level || '').toUpperCase();
const validLevels = ['DEBUG', 'INFO', 'WARNING', 'ERROR', 'CRITICAL', 'FATAL'];
const normalizedLevel = validLevels.includes(level) ? level : 'ERROR';

// Parse stack trace if present
const stackTrace = body.stack_trace || body.stackTrace || body.stack || null;
const stackLines = stackTrace ? stackTrace.split('\n').slice(0, 20).join('\n') : null;

// Extract error type from message or stack
let errorType = body.error_type || body.errorType || null;
if (!errorType && stackTrace) {
  const match = stackTrace.match(/^([A-Za-z]+(?:Error|Exception|Fault|Warning))/);
  errorType = match ? match[1] : 'UnknownError';
} else if (!errorType) {
  const match = body.message.match(/([A-Za-z]+(?:Error|Exception|Fault))/);
  errorType = match ? match[1] : 'ApplicationError';
}

const searchKeyword = `[${body.service}] ${errorType}`;

const enrichedLog = {
  service: body.service,
  environment: body.environment || body.env || 'production',
  level: normalizedLevel,
  isCritical: ['CRITICAL', 'FATAL'].includes(normalizedLevel) || body.isCritical === true,
  message: body.message,
  errorType,
  timestamp: body.timestamp || new Date().toISOString(),
  traceId: body.trace_id || body.traceId || null,
  userId: body.user_id || body.userId || null,
  endpoint: body.endpoint || body.path || null,
  httpMethod: body.http_method || body.method || null,
  statusCode: body.status_code || body.statusCode || null,
  stackTrace: stackLines,
  stackRaw: stackTrace ? stackTrace.substring(0, 3000) : null,
  searchKeyword,
  rawLog: JSON.stringify(body).substring(0, 2000)
};

return [{ json: enrichedLog }];

// ========================================
// Node: Duplicate Issue Check
// ========================================
const log = $('Parse and Enrich Log').first().json;
const issues = $input.all().map(i => i.json);

const service = log.service || '';
const errorType = log.errorType || '';
const message = (log.message || '').toLowerCase().substring(0, 100);

let bestMatch = null;
let bestScore = 0;

for (const issue of issues) {
  if (!issue || !issue.title) continue;

  let score = 0;
  const title = (issue.title || '').toLowerCase();
  const body = (issue.body || '').toLowerCase();

  if (title.includes(service.toLowerCase())) score += 40;
  if (title.includes(errorType.toLowerCase())) score += 40;

  const words = message.split(' ').filter(w => w.length > 4);
  const wordMatches = words.filter(w => title.includes(w) || body.includes(w)).length;
  score += Math.min(wordMatches * 5, 20);

  if (score > bestScore) {
    bestScore = score;
    bestMatch = issue;
  }
}

const isDuplicate = bestScore >= 60;

return [{
  json: {
    ...log,
    duplicateCheck: {
      isDuplicate,
      score: bestScore,
      matchedIssue: isDuplicate ? {
        number: bestMatch.number,
        title: bestMatch.title,
        url: bestMatch.html_url,
        state: bestMatch.state,
        createdAt: bestMatch.created_at
      } : null,
      totalIssuesChecked: issues.length
    }
  }
}];

// ========================================
// Node: Parse OpenAI Analysis
// ========================================
const log = $('Score GitHub Issue Duplicates').first().json;
const aiResponse = $input.first().json;

let rawContent = '';
if (aiResponse.message && aiResponse.message.content) {
  rawContent = aiResponse.message.content;
} else if (aiResponse.choices && aiResponse.choices[0]) {
  rawContent = aiResponse.choices[0].message?.content || '';
} else if (typeof aiResponse === 'string') {
  rawContent = aiResponse;
}

let analysis = {};
try {
  const jsonMatch = rawContent.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    analysis = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('No JSON found in response');
  }
} catch (e) {
  analysis = {
    summary: `${log.errorType} in ${log.service}: ${log.message.substring(0, 80)}`,
    rootCause: 'Automated analysis could not parse AI response. Manual review required.',
    impact: 'Unknown - requires manual assessment',
    severity: log.isCritical ? 'CRITICAL' : 'HIGH',
    category: log.errorType,
    fixSuggestions: [{ step: 1, title: 'Manual Review', description: 'Review the error logs manually and investigate the root cause.', codeExample: '' }],
    preventionMeasures: ['Add monitoring alerts', 'Review error handling logic'],
    estimatedEffort: 'M',
    relatedComponents: [log.service],
    labels: ['bug', 'auto-generated', 'needs-review']
  };
}

const fixSteps = (analysis.fixSuggestions || []).map(s => {
  let step = `### Step ${s.step}: ${s.title}
${s.description}`;
  if (s.codeExample) step += `

\`\`\`
${s.codeExample}
\`\`\``;
  return step;
}).join('

');

const prevention = (analysis.preventionMeasures || []).map(m => `- ${m}`).join('
');
const components = (analysis.relatedComponents || []).map(c => `\`${c}\``).join(', ');

const issueTitle = `[${log.service}] ${analysis.summary || log.message.substring(0, 100)}`;

const issueBody = `## 🐛 Error Report

> **Auto-generated by AI Error Log Analyzer** | ${new Date().toUTCString()}

---

## 📋 Error Details

| Field | Value |
|-------|-------|
| **Service** | \`${log.service}\` |
| **Environment** | \`${log.environment}\` |
| **Severity** | \`${analysis.severity || log.level}\` |
| **Category** | \`${analysis.category || log.errorType}\` |
| **Error Type** | \`${log.errorType}\` |
| **Timestamp** | \`${log.timestamp}\` |
| **Trace ID** | \`${log.traceId || 'N/A'}\` |
| **Estimated Effort** | \`${analysis.estimatedEffort || 'M'}\` |
| **Affected Components** | ${components || 'N/A'} |

---

## 💬 Error Message

\`\`\`
${log.message}
\`\`\`

${log.stackTrace ? `## 📍 Stack Trace

\`\`\`
${log.stackTrace}
\`\`\`` : ''}

---

## 🔍 Root Cause Analysis

${analysis.rootCause}

**Potential Impact:** ${analysis.impact}

---

## 🛠️ Suggested Fixes

${fixSteps}

---

## 🛡️ Prevention Measures

${prevention}

---

## 🔗 Additional Context

<details>
<summary>Request Details</summary>

- **Endpoint:** \`${log.endpoint || 'N/A'}\`
- **Method:** \`${log.httpMethod || 'N/A'}\`
- **Status Code:** \`${log.statusCode || 'N/A'}\`
- **User ID:** \`${log.userId || 'N/A'}\`

</details>

---
*This issue was automatically created by the AI Error Log Analyzer workflow.*`;

const labels = analysis.labels || ['bug', 'auto-generated'];
if (log.isCritical && !labels.includes('critical')) labels.push('critical');
if (!labels.includes(log.environment)) labels.push(log.environment);

return [{
  json: {
    ...log,
    analysis,
    issueTitle,
    issueBody,
    labels
  }
}];

